        printf("Memory allocation failed.\n");
        return 1;
    }

    printf("Enter %d elements for the sequential table:\n", size);
    for (int i = 0; i < size; i++) {
        printf("Element %d: ", i+1);
        scanf("%d", &table[i]);
    }

    // Display the created table
